package main

import (
    "sync"
    "sync/atomic"
    "time"
)

type Bank struct {
    accounts map[string]*Account
    mutex    sync.RWMutex
}

type Account struct {
    Balance int64
    ID      string
}

type Transaction struct {
    AccountID string
    Amount    int64
    Type      string // "deposit" or "withdraw"
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]*Account),
    }
}

func (b *Bank) GetBalance(accountID string) int64 {
    b.mutex.RLock()
    defer b.mutex.RUnlock()
    
    account, exists := b.accounts[accountID]
    if !exists {
        return 0
    }
    return account.Balance
}

func (b *Bank) ProcessTransaction(tx Transaction) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    
    account, exists := b.accounts[tx.AccountID]
    if !exists {
        account = &Account{ID: tx.AccountID, Balance: 0}
        b.accounts[tx.AccountID] = account
    }
    
    if tx.Type == "withdraw" {
        if account.Balance < tx.Amount {
            return ErrInsufficientFunds
        }
        account.Balance -= tx.Amount
    } else if tx.Type == "deposit" {
        account.Balance += tx.Amount
    } else {
        return ErrInvalidTransactionType
    }
    
    return nil
}

func (b *Bank) Transfer(fromAccountID, toAccountID string, amount int64) error {
    if fromAccountID == toAccountID {
        return nil
    }
    
    b.mutex.Lock()
    defer b.mutex.Unlock()
    
    fromAccount, fromExists := b.accounts[fromAccountID]
    toAccount, toExists := b.accounts[toAccountID]
    
    if !fromExists || fromAccount.Balance < amount {
        return ErrInsufficientFunds
    }
    
    if !toExists {
        toAccount = &Account{ID: toAccountID, Balance: 0}
        b.accounts[toAccountID] = toAccount
    }
    
    fromAccount.Balance -= amount
    toAccount.Balance += amount
    
    return nil
}

func (b *Bank) ConcurrentTransfer(fromAccountID, toAccountID string, amount int64, numGoroutines int) error {
    if fromAccountID == toAccountID {
        return nil
    }
    
    var wg sync.WaitGroup
    errors := make(chan error, numGoroutines)
    
    for i := 0; i < numGoroutines; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            err := b.Transfer(fromAccountID, toAccountID, amount)
            errors <- err
        }()
    }
    
    wg.Wait()
    close(errors)
    
    for err := range errors {
        if err != nil {
            return err
        }
    }
    
    return nil
}

var (
    ErrInsufficientFunds     = &BankError{"insufficient funds"}
    ErrInvalidTransactionType = &BankError{"invalid transaction type"}
)

type BankError struct {
    msg string
}

func (e *BankError) Error() string {
    return e.msg
}

func (b *Bank) ProcessConcurrentTransactions(transactions []Transaction, numGoroutines int) error {
    var wg sync.WaitGroup
    errors := make(chan error, len(transactions))
    
    for i := 0; i < numGoroutines; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for _, tx := range transactions {
                err := b.ProcessTransaction(tx)
                if err != nil {
                    errors <- err
                    return
                }
            }
        }()
    }
    
    wg.Wait()
    close(errors)
    
    for err := range errors {
        if err != nil {
            return err
        }
    }
    
    return nil
}